action:
S_U[X;\theta]
=
S_{\mathrm{graph}}
+S_{\mathrm{spec}}
+S_{\mathrm{gauge}}
+S_{\mathrm{matter}}
+S_{\mathrm{mass}}
+S_{\mathrm{mix}}
+S_{\mathrm{reg}}
+S_{\mathrm{obs}}
+S_{\mathrm{penalty}}

X =
(
\mathcal G,\,
g_{ij},\,
L_A,\,
\rho(\lambda),\,
A_\mu,\,
W_\mu^a,\,
G_\mu^a,\,
\Phi,\,
\psi_f,\,
\sigma_n
)

S_{\mathrm{graph}}
=
\sum_{(i,j)\in E}
w_{ij}
\left[
\alpha_R R_{ij}(L_A)
+\alpha_\Delta (d_i-K)^2
+\alpha_p(\bar p-p)^2
\right]

S_{\mathrm{spec}}
=
\sum_{n=0}^{M}
\rho_n
\left[
\lambda_n
+\beta_2\lambda_n^2
+\beta_{\log}\log(1+\lambda_n)
\right]
e^{-\sigma_n n}

S_{\mathrm{gauge}}
=
\sum_x
\left[
\frac{1}{4g_1^2}F_{\mu\nu}F^{\mu\nu}
+\frac{1}{4g_2^2}W_{\mu\nu}^aW^{a\mu\nu}
+\frac{1}{4g_3^2}G_{\mu\nu}^aG^{a\mu\nu}
\right]_x

S_{\mathrm{matter}}
=
\sum_{x,f}
\bar\psi_f
\left(
i\gamma^\mu D_\mu
-y_f\Phi
\right)
\psi_f

S_{\mathrm{mass}}
=
\sum_a
\left[
\mu_a
-
m_e C_a
\prod_{r=1}^{6} f_r^{q_{ar}}
\right]^2

S_{\mathrm{mix}}
=
\sum_{a<b}
\eta_{ab}
\left\langle
\Psi_a,\Psi_b
\right\rangle_L

S_{\mathrm{reg}}
=
\sum_n
\left[
\gamma_1\sigma_n^2
+\gamma_2(\sigma_{n+1}-\sigma_n)^2
\right],
\qquad
\sigma_n>0

S_{\mathrm{obs}}
=
\sum_{k\in\mathcal T_{\mathrm{train}}}
\omega_k
\left[
\log O_k(X)-\log O_k^{\mathrm{obs}}
\right]^2

S_{\mathrm{penalty}}
=
\lambda_{\mathrm{dof}}\mathrm{DOF}(\theta)
+\lambda_{\mathrm{fit}}
\sum_a \mathbf 1[C_a\ \mathrm{is\ fitted}]
+\lambda_{\mathrm{leak}}\mathrm{Leakage}(\theta,\mathcal T_{\mathrm{test}})
